/**
 * Analytics models for the dashboard API.
 */

/**
 * Aggregated summary statistics across the platform.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics data.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date | null;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

/**
 * Analytics service — aggregates data from repositories for dashboard insights.
 *
 * Depends on:
 * - UserRepository (data layer) for user data
 * - OrderRepository (data layer) for order data
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get aggregated platform summary statistics.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    const userIdsWithOrders = new Set(orders.map((order) => order.userId));
    const activeUsers = userIdsWithOrders.size;

    return {
      totalUsers: users.length,
      totalOrders: orders.length,
      revenue,
      activeUsers,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    const lastActive = orders.length > 0
      ? orders.reduce((latest, order) =>
          order.createdAt > latest ? order.createdAt : latest,
        orders[0].createdAt)
      : null;

    return {
      userId,
      orderCount: orders.length,
      totalSpent,
      lastActive,
    };
  }

  /**
   * Get time-series trend data for a metric within a date range.
   *
   * Supported metrics: "orders" and "revenue".
   * Returns one TrendPoint per day in the range.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric}`);

    if (metric !== 'orders' && metric !== 'revenue') {
      throw new Error(`Unsupported metric: ${metric}`);
    }

    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    // Group orders by day
    const buckets = new Map<string, number>();
    for (const order of orders) {
      const dayKey = order.createdAt.toISOString().split('T')[0];
      const value = metric === 'revenue' ? order.total : 1;
      buckets.set(dayKey, (buckets.get(dayKey) ?? 0) + value);
    }

    // Build trend points for each day in the range
    const points: TrendPoint[] = [];
    const current = new Date(startDate);
    while (current <= endDate) {
      const dayKey = current.toISOString().split('T')[0];
      points.push({
        timestamp: new Date(current),
        metric,
        value: buckets.get(dayKey) ?? 0,
      });
      current.setDate(current.getDate() + 1);
    }

    return points;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2026-01-01'),
    updatedAt: new Date('2026-01-01'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 50 }],
    total: 50,
    status: 'pending',
    createdAt: new Date('2026-01-15'),
    updatedAt: new Date('2026-01-15'),
    ...overrides,
  };
}

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should aggregate stats from users and orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));
      userRepo.save(makeUser({ id: 'user-3', email: 'carol@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'order-3', userId: 'user-2', total: 75 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(3);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(225);
      expect(summary.activeUsers).toBe(2);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });

    it('should return zero stats for user with no orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toBeNull();
    });

    it('should aggregate per-user order data', () => {
      userRepo.save(makeUser({ id: 'user-1' }));

      orderRepo.save(makeOrder({
        id: 'order-1',
        userId: 'user-1',
        total: 100,
        createdAt: new Date('2026-01-10'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        userId: 'user-1',
        total: 50,
        createdAt: new Date('2026-02-20'),
      }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(150);
      expect(analytics.lastActive).toEqual(new Date('2026-02-20'));
    });
  });

  describe('getTrends', () => {
    it('should throw for unsupported metric', () => {
      expect(() =>
        service.getTrends('invalid', new Date('2026-01-01'), new Date('2026-01-03')),
      ).toThrow('Unsupported metric');
    });

    it('should return zero-filled points when no orders exist', () => {
      const points = service.getTrends('orders', new Date('2026-01-01'), new Date('2026-01-03'));

      expect(points).toHaveLength(3);
      expect(points.every((p) => p.value === 0)).toBe(true);
      expect(points.every((p) => p.metric === 'orders')).toBe(true);
    });

    it('should aggregate order counts by day', () => {
      userRepo.save(makeUser({ id: 'user-1' }));

      orderRepo.save(makeOrder({
        id: 'order-1',
        createdAt: new Date('2026-01-01T10:00:00Z'),
        total: 100,
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        createdAt: new Date('2026-01-01T14:00:00Z'),
        total: 50,
      }));
      orderRepo.save(makeOrder({
        id: 'order-3',
        createdAt: new Date('2026-01-03T08:00:00Z'),
        total: 75,
      }));

      const points = service.getTrends('orders', new Date('2026-01-01'), new Date('2026-01-03'));

      expect(points).toHaveLength(3);
      expect(points[0].value).toBe(2); // Jan 1: two orders
      expect(points[1].value).toBe(0); // Jan 2: none
      expect(points[2].value).toBe(1); // Jan 3: one order
    });

    it('should aggregate revenue by day', () => {
      userRepo.save(makeUser({ id: 'user-1' }));

      orderRepo.save(makeOrder({
        id: 'order-1',
        createdAt: new Date('2026-01-01T10:00:00Z'),
        total: 100,
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        createdAt: new Date('2026-01-01T14:00:00Z'),
        total: 50,
      }));
      orderRepo.save(makeOrder({
        id: 'order-3',
        createdAt: new Date('2026-01-02T08:00:00Z'),
        total: 75,
      }));

      const points = service.getTrends('revenue', new Date('2026-01-01'), new Date('2026-01-02'));

      expect(points).toHaveLength(2);
      expect(points[0].value).toBe(150); // Jan 1: 100 + 50
      expect(points[1].value).toBe(75);  // Jan 2: 75
    });
  });
});

